#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N,X,K,P; scanf("%lld %lld %lld %lld", &N, &X, &K, &P);
        long long first = (K < X ? K : X) * 10LL;
        long long rest = (K > X ? (K - X) * 5LL : 0LL);
        long long bonus = (K == N ? 20LL : 0LL);
        printf("%lld\n", P + first + rest + bonus);
    }
    return 0;
}

